from __future__ import annotations
import base64,json,lzma
from pathlib import Path
DATA=''
payload=json.loads(lzma.decompress(base64.b64decode(DATA)))
Path('src/lib/newsletter/post-draft-dossier.ts').write_text(payload['module'],encoding='utf-8')
ns={'__name__':'__main__','__file__':'scripts/apply-post-draft-dossier.py'}
exec(compile(payload['patch'],'scripts/apply-post-draft-dossier.py','exec'),ns,ns)
